DROP TABLE IF EXISTS `tb_tournament`;
CREATE TABLE `tb_tournament`  (
  `id` bigint(0) NOT NULL AUTO_INCREMENT COMMENT '比赛ID',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '比赛名称',
  `cover` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '封面地址',
  `description` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '比赛摘要',
  `max_number` int(0) NULL DEFAULT NULL COMMENT '最大参赛次数',
  `participants_number` int(0) NULL DEFAULT 0 COMMENT '参与人数',
  `text` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '内容',
  `registration_time_start` datetime(0) NULL DEFAULT NULL COMMENT '报名开始时间',
  `registration_time_end` datetime(0) NULL DEFAULT NULL COMMENT '报名结束时间',
  `tournament_time_start` datetime(0) NULL DEFAULT NULL COMMENT '比赛开始时间',
  `tournament_time_end` datetime(0) NULL DEFAULT NULL COMMENT '比赛结束时间',
  `registration_is` tinyint(1) NULL DEFAULT NULL COMMENT '报名开始状态(0 报名开始，1报名未开始)',
  `tournament_is` tinyint(1) NULL DEFAULT NULL COMMENT '比赛开始状态(0 比赛开始，比赛未开始)',
  `del_flag` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '0' COMMENT '删除标志（0代表存在 2代表删除）',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '创建者',
  `create_time` datetime(0) NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '更新者',
  `update_time` datetime(0) NULL DEFAULT NULL COMMENT '更新时间',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '备注',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 14 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '比赛信息表' ROW_FORMAT = Dynamic;

