-- ----------------------------
-- Table structure for tb_tournament_group
-- ----------------------------
DROP TABLE IF EXISTS `tb_tournament_group`;
CREATE TABLE `tb_tournament_group`  (
  `id` bigint(0) NOT NULL AUTO_INCREMENT COMMENT '比赛分组ID',
  `tournament_id` bigint(0) NULL DEFAULT NULL COMMENT '比赛ID',
  `name` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '分组名称',
  `sex` tinyint(1) NULL DEFAULT NULL COMMENT '0 女， 1 男',
  `distance` int(0) NULL DEFAULT NULL COMMENT '距离（米）',
  `del_state` int(0) NULL DEFAULT 0 COMMENT '0 未删除；1 删除',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '创建者',
  `create_time` datetime(0) NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '更新者',
  `update_time` datetime(0) NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 32 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '比赛分组表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of tb_tournament_group
-- ----------------------------

-- ----------------------------
-- Table structure for tb_tournament_group_user
-- ----------------------------
DROP TABLE IF EXISTS `tb_tournament_group_user`;
CREATE TABLE `tb_tournament_group_user`  (
  `id` bigint(0) NOT NULL AUTO_INCREMENT COMMENT '参赛ID',
  `tournament_group_id` bigint(0) NULL DEFAULT NULL COMMENT '比赛分组ID',
  `user_id` bigint(0) NULL DEFAULT NULL COMMENT '用户ID',
  `time` time(0) NULL DEFAULT NULL COMMENT '跑步时长',
  `speed` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '平均配速',
  `kcal` bigint(0) NULL DEFAULT NULL COMMENT '卡路里(cal)',
  `distance` bigint(0) NULL DEFAULT NULL COMMENT '距离(厘米cm)',
  `km_speed` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '公里速度',
  `points` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '路径定位',
  `altitude` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '海拔',
  `altitude_sum` bigint(0) NULL DEFAULT NULL COMMENT '爬升高度',
  `run_type` int(0) NULL DEFAULT NULL COMMENT '跑步类型',
  `step` int(0) NULL DEFAULT NULL COMMENT '步数',
  `state` int(0) NULL DEFAULT 2 COMMENT '状态(0 有效，1无效成绩，2已报名未参赛)',
  `del_state` int(0) NULL DEFAULT 0 COMMENT '0 未删除；1 删除',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '创建者',
  `create_time` datetime(0) NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '更新者',
  `update_time` datetime(0) NULL DEFAULT NULL COMMENT '跑步时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `groupId`(`tournament_group_id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '用户比赛跑步数据表' ROW_FORMAT = Dynamic;

