  `unionid` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '用户在开放平台的唯一标识符（预留字段）',
  `weight` int(0) NULL DEFAULT NULL COMMENT '体重Kg',
  `height` int(0) NULL DEFAULT NULL COMMENT '身高cm',
